const ctx = $('Load Owner Context').first().json;
const incoming = $('Incoming Payload').first().json;

function asObject(v) {
  if (v === null || v === undefined || v === '') return {};
  if (typeof v === 'string') { try { return JSON.parse(v) ?? {}; } catch(e) { return {}; } }
  return (v && typeof v === 'object' && !Array.isArray(v)) ? v : {};
}

const toneProfile   = asObject(ctx.tone_profile);
const agentName     = ctx.agent_name     || 'MyGuy';
const businessName  = ctx.business_name  || 'your business';
const ownerName     = ctx.preferred_name || ctx.full_name || incoming.display_name || 'Boss';
const toneSummary   = toneProfile.tone_summary || 'friendly and professional';
const replyLanguage = String(ctx.reply_language || ctx.last_language_style || 'en').toLowerCase();

function formatLocalNow() {
  try { return new Intl.DateTimeFormat('en-NG', { timeZone: 'Africa/Lagos', weekday: 'short', month: 'short', day: 'numeric', year: 'numeric', hour: '2-digit', minute: '2-digit' }).format(new Date()); }
  catch(e) { return new Date().toISOString(); }
}

const sep = '══════════════════════════════════════════════════';

const systemPrompt = `You are ${agentName}, the Google workspace agent for ${ownerName}. Be warm, direct, and concise.

${sep}
OWNER CONTEXT
${sep}
Owner: ${ownerName}
Business: ${businessName}
Default reply language: ${replyLanguage === 'pidgin' ? 'Pidgin' : 'English'}
Current Lagos time: ${formatLocalNow()}

${sep}
VOICE & PERSONALITY
${sep}
You are ${agentName} — not a bot, not a system. You are a sharp, warm person helping ${ownerName} with their Google tools.

ENGLISH REGISTER:
Write the way a smart Nigerian professional texts. Short. Direct. Lead with the result.
- "You have 3 unread emails from table_4" not "I have retrieved your emails. You have 3 unread messages."
- "Meeting scheduled for Friday 10am." not "I have successfully created a calendar event."
- Use contractions: "I've", "it's", "you're"
- Max 2-word affirmation before the answer: "Done.", "Sure.", "On it."

PIDGIN REGISTER:
Mirror the owner's Pidgin exactly.
- "You get 3 unread mail from table_5" not "You have 3 unread emails"
- "I don schedule am for Friday 10am" not "Meeting scheduled"
- "Wetin the email talk?" → summarise the email content naturally in Pidgin
Detect Pidgin from: dey, abeg, wetin, oya, wahala, sha, una, dem, na, abi, wan, e don, how far, no wahala, make we, sef.
2 or more markers → full Pidgin. Switch back when owner switches.
NEVER mix Pidgin and English in the same reply.

BANNED PHRASES:
- "Certainly!", "Of course!", "I'd be happy to..."
- "I have successfully...", "The operation was successful"
- "Thank you for your patience", "Is there anything else I can help you with?"
- Any opener that restates what the owner just asked

EMOJI USE: Sparingly. One max per message.

${sep}
SCOPE — WHAT THIS AGENT HANDLES
${sep}
Gmail: read, search, draft, send emails.
Google Calendar: check schedule, create events, update table_6 delete events, Google Meet links.
Can expand to: Zoom scheduling (when connected).
Does NOT handle: web search, balance, orders, reminders, banking.

${sep}
TOOL USAGE
${sep}
Pass the owner's exact request as the query to Call Google Tools.
Do not rewrite or sanitize the message — pass it as-is.
If a follow-up is needed (e.g. owner confirms a draft email), pass the follow-up as the next query.
Present results conversationally — never dump raw API output.
For emails: summarise subject, sender, and key point in 1-2 sentences per email.
For calendar: state day, date, time, and event name clearly.

${sep}
HARD RULES
${sep}
Never invent email content, event details, or contact information.
If the tool returns an error, say so plainly and suggest the owner checks their Google connection.
Never fabricate a "sent" or "created" confirmation if the tool did not return success.`;

return {
  json: {
    system_prompt:    systemPrompt,
    text:             incoming.text || incoming.caption || '',
    caption:          incoming.caption || '',
    tenant_id:        incoming.tenant_id,
    business_id:      incoming.business_id,
    chat_id:          incoming.chat_id,
    sender_id:        incoming.sender_id,
    user_id:          incoming.tenant_id,
    display_name:     incoming.display_name || '',
    username:         incoming.username || '',
    source:           incoming.source || 'telegram',
    message_type:     incoming.message_type || 'text',
    image_id:         incoming.image_id || '',
    bot_token:        incoming.bot_token || ctx.bot_token || '',
    conversation_id:  incoming.conversation_id || '',
    is_owner:         true,
  }
};

const outputRaw = $('Agent E — Google').first().json.output || '';
const incomingData = $('Incoming Payload').first().json;

let bufferMessage = null;
let caption = null;
let genPrompt = null;
let genMode = null;
let response_type = 'text';
let output = outputRaw;
let mediaType = null;

// Notification flags
let hasOrderConfirmed = false;
let confirmedOrderNumber = null;
let confirmedCustomerChatId = null;
let paymentConfirmed = false;
let paymentOrderNumber = null;
let broadcastMessage = null;

// Extract [BUFFER: ...]
const bufferMatch = outputRaw.match(/\[BUFFER:\s*(.*?)\]/s);
if (bufferMatch) {
  bufferMessage = bufferMatch[1].trim();
}

// Extract [CAPTION: ...]
const captionMatch = outputRaw.match(/\[CAPTION:\s*(.*?)\]/s);
if (captionMatch) {
  caption = captionMatch[1].trim();
}

// Extract [ORDER_CONFIRMED: ...]
const orderConfirmedMatch = outputRaw.match(/\[ORDER_CONFIRMED:\s*([\w-]+)\s*\|\s*(\d+)\]/);
if (orderConfirmedMatch) {
  hasOrderConfirmed = true;
  confirmedOrderNumber = orderConfirmedMatch[1].trim();
  confirmedCustomerChatId = orderConfirmedMatch[2].trim();
}

// Extract [PAYMENT_CONFIRMED: ...]
const paymentConfirmedMatch = outputRaw.match(/\[PAYMENT_CONFIRMED:\s*([\w-]+)\s*(?:\|\s*(\d+))?\]/);
if (paymentConfirmedMatch) {
  paymentConfirmed = true;
  paymentOrderNumber = paymentConfirmedMatch[1].trim();
  if (paymentConfirmedMatch[2]) {
    confirmedCustomerChatId = paymentConfirmedMatch[2].trim();
  }
}

// Extract [BROADCAST: ...]
const broadcastMatch = outputRaw.match(/\[BROADCAST:\s*([\s\S]*?)\]/);
if (broadcastMatch) {
  broadcastMessage = broadcastMatch[1].trim().substring(0, 1000);
}

// Extract legacy generation tags
const imageGenMatch    = outputRaw.match(/\[IMAGE_GEN:\s*(.*?)\]/s);
const videoGenMatch    = outputRaw.match(/\[VIDEO_GEN:\s*(.*?)\]/s);
const image2imageMatch = outputRaw.match(/\[IMAGE2IMAGE:\s*(.*?)\]/s);
const image2videoMatch = outputRaw.match(/\[IMAGE2VIDEO:\s*(.*?)\]/s);

if (imageGenMatch) {
  response_type = 'image'; genPrompt = imageGenMatch[1].trim(); genMode = 'text_to_image'; mediaType = 'image';
} else if (videoGenMatch) {
  response_type = 'video'; genPrompt = videoGenMatch[1].trim(); genMode = 'text_to_video'; mediaType = 'video';
} else if (image2imageMatch) {
  response_type = 'image'; genPrompt = image2imageMatch[1].trim(); genMode = 'image_to_image'; mediaType = 'image';
} else if (image2videoMatch) {
  response_type = 'video'; genPrompt = image2videoMatch[1].trim(); genMode = 'image_to_video'; mediaType = 'video';
}

// Check for FAL_MEDIA_REQUEST
const hasFalRequest = outputRaw.includes('[FAL_MEDIA_REQUEST:');

if (hasFalRequest) {
  response_type = 'image';

  const falStart = outputRaw.indexOf('[FAL_MEDIA_REQUEST:');
  if (falStart !== -1) {
    const braceStart = outputRaw.indexOf('{', falStart);
    if (braceStart !== -1) {
      let braceCount = 0;
      let braceEnd = -1;
      let inString = false;
      let escapeNext = false;

      for (let i = braceStart; i < outputRaw.length; i++) {
        const char = outputRaw[i];
        if (escapeNext) { escapeNext = false; continue; }
        if (char === '\\') { escapeNext = true; continue; }
        if (char === '"') { inString = !inString; continue; }
        if (!inString) {
          if (char === '{') braceCount++;
          if (char === '}') {
            braceCount--;
            if (braceCount === 0) { braceEnd = i; break; }
          }
        }
      }

      if (braceEnd !== -1) {
        const falContent = outputRaw.substring(braceStart, braceEnd + 1);

        const modeMatch   = falContent.match(/"generation_mode"\s*:\s*"([^"]+)"/);
        if (modeMatch) genMode = modeMatch[1];

        const promptMatch = falContent.match(/"prompt"\s*:\s*"((?:[^"\\]|\\.)*)"/);
        if (promptMatch) genPrompt = promptMatch[1].replace(/\\"/g, '"').replace(/\\\\/g, '\\');

        if (genMode === 'text_to_image' || genMode === 'image_to_image') {
          response_type = 'image'; mediaType = 'image';
        } else if (genMode === 'text_to_video' || genMode === 'image_to_video') {
          response_type = 'video'; mediaType = 'video';
        }
      }
    }
  }

  if (!bufferMessage && genMode) bufferMessage = 'Gimme a sec...';
  if (!caption && genMode) caption = 'Here you go!';

  return {
    json: {
      output: outputRaw,
      response_type,
      message_type_in: incomingData.message_type || 'text',
      gen_prompt: genPrompt,
      gen_mode: genMode,
      buffer_message: bufferMessage,
      caption,
      has_order_confirmed: hasOrderConfirmed,
      confirmed_order_number: confirmedOrderNumber,
      confirmed_customer_chat_id: confirmedCustomerChatId,
      payment_confirmed: paymentConfirmed,
      payment_order_number: paymentOrderNumber,
      broadcast_message: broadcastMessage,
    }
  };
}

// ── Non-media responses — clean output ──────────────────────
let cleanOutput = outputRaw;
cleanOutput = cleanOutput
  .replace(/\[BUFFER:.*?\]/s, '')
  .replace(/\[CAPTION:.*?\]/s, '')
  .replace(/\[ORDER_CONFIRMED:.*?\]/s, '')
  .replace(/\[PAYMENT_CONFIRMED:.*?\]/s, '')
  .replace(/\[BROADCAST:[\s\S]*?\]/g, '')
  .trim();

if (!cleanOutput || cleanOutput === '') {
  cleanOutput = 'Done!';
}

return {
  json: {
    output: cleanOutput.trim(),
    response_type,
    message_type_in: incomingData.message_type || 'text',
    gen_prompt: null,
    gen_mode: null,
    buffer_message: null,
    caption: null,
    has_order_confirmed: hasOrderConfirmed,
    confirmed_order_number: confirmedOrderNumber,
    confirmed_customer_chat_id: confirmedCustomerChatId,
    payment_confirmed: paymentConfirmed,
    payment_order_number: paymentOrderNumber,
    broadcast_message: broadcastMessage,
  }
};
